# 阶乘递归
def factorial(n):
    if n == 0:           # 基准条件
        return 1
    return n * factorial(n - 1)  # 递归调用

print(factorial(5))  # 120

# 斐波那契递归
def fibonacci(n):
    if n <= 1:
        return n
    return fibonacci(n-1) + fibonacci(n-2)

print(fibonacci(10))  # 55

# 递归求和
def sum_list(lst):
    if not lst:
        return 0
    return lst[0] + sum_list(lst[1:])

