# 继承
class Animal:
    def speak(self):
        pass

class Dog(Animal):
    def speak(self):
        return "Woof!"

class Cat(Animal):
    def speak(self):
        return "Meow!"

# 多态
animals = [Dog(), Cat()]
for animal in animals:
    print(animal.speak())  # Woof! Meow!

# super调用父类
class Bird(Animal):
    def __init__(self, name):
        self.name = name
        super().__init__()

    def speak(self):
        return f"{self.name} sings"

